const input = (items[0] && items[0].json) ? items[0].json : {};

const now = new Date();
const stamp = now.toISOString().replace(/[-:.TZ]/g, '').slice(0, 14);
const executionId = ($execution && $execution.id) ? String($execution.id) : String(input.execution_id || 'manual');
const workflowKey = 'wf90';
const runId = workflowKey + '-' + executionId + '-' + stamp;

function parseBool(value, fallback = false) {
  if (value === true || value === false) return value;
  const normalized = String(value == null ? '' : value).toLowerCase();
  if (normalized === 'true') return true;
  if (normalized === 'false') return false;
  return fallback;
}

function parseNumber(value, fallback) {
  const num = Number(value);
  return Number.isFinite(num) ? num : fallback;
}

const model = String(input.model || $env.OLLAMA_MODEL || 'qwen3.5:27b');

const context = {
  run_id: runId,
  execution_id: executionId,
  workflow_key: workflowKey,
  workflow_name: 'WF90 Orchestrator Subflows',
  created_at: now.toISOString(),
  completed_at: null,
  status: 'running',

  topic_hint: String(input.topic || ''),
  model_primary: model,
  model_used: model,

  quality_gate: {
    min_quality_score: parseNumber($env.WF90_MIN_QUALITY_SCORE, 6.5),
    min_evidence_refs: parseNumber($env.WF90_MIN_EVIDENCE_REFS, 3),
    min_draft_body_len: parseNumber($env.WF90_MIN_DRAFT_BODY_LEN, 180),
  },

  workflow_dir: input.workflow_dir || $env.OBSIDIAN_WORKFLOW_DIR || 'Marketing/Social-Media/Workflow',
  workflow_logs_dir: input.workflow_logs_dir || $env.OBSIDIAN_WORKFLOW_LOGS_DIR || 'Marketing/Social-Media/Workflow/Workflow Logs',
  workflow_results_dir: input.workflow_results_dir || $env.OBSIDIAN_WORKFLOW_RESULTS_DIR || 'Marketing/Social-Media/Workflow/Workflow Ergebnisse',
  workflow_drafts_dir: input.workflow_drafts_dir || $env.OBSIDIAN_WORKFLOW_DRAFTS_DIR || 'Marketing/Social-Media/Workflow/Drafts',
  workflow_prompts_dir: input.workflow_prompts_dir || $env.OBSIDIAN_WORKFLOW_PROMPTS_DIR || 'Marketing/Social-Media/Workflow/Prompts',

  workflow_results_index: input.workflow_results_index || $env.OBSIDIAN_WORKFLOW_RESULTS_INDEX || 'Marketing/Social-Media/Workflow/Workflow Ergebnisse/00-Workflow-Ergebnisse.md',
  workflow_steps_file: input.workflow_steps_file || $env.OBSIDIAN_WORKFLOW_STEPS_FILE || 'Marketing/Social-Media/Workflow/Workflow Schritte.md',
  workflow_intermediate_file: input.workflow_intermediate_file || $env.OBSIDIAN_WORKFLOW_INTERMEDIATE_FILE || 'Marketing/Social-Media/Workflow/Workflow Zwischenergebnisse.md',
  workflow_overview_file: input.workflow_overview_file || $env.OBSIDIAN_WORKFLOW_OVERVIEW_FILE || 'Marketing/Social-Media/Workflow/Workflow Übersicht.md',

  obsidian_rest_url: input.obsidian_rest_url || $env.OBSIDIAN_REST_URL || '',
  obsidian_rest_api_key: input.obsidian_rest_api_key || $env.OBSIDIAN_REST_API_KEY || '',
  allow_insecure_tls: parseBool(input.allow_insecure_tls, parseBool($env.OBSIDIAN_ALLOW_INSECURE_TLS, false)),

  prompts: {},
  model_trace: Array.isArray(input.model_trace) ? input.model_trace : [],
  stage_logs: Array.isArray(input.stage_logs) ? input.stage_logs : [],
  stage_summaries: Array.isArray(input.stage_summaries) ? input.stage_summaries : [],
  artifacts: (input.artifacts && typeof input.artifacts === 'object') ? input.artifacts : {},

  output_paths: (input.output_paths && typeof input.output_paths === 'object') ? input.output_paths : {},
  generated: (input.generated && typeof input.generated === 'object') ? input.generated : {},
};

return [{ json: context }];

const ctx = items[0].json;

if (!ctx.obsidian_rest_url || !ctx.obsidian_rest_api_key) {
  throw new Error('Missing OBSIDIAN_REST_URL or OBSIDIAN_REST_API_KEY');
}

const baseUrl = String(ctx.obsidian_rest_url).replace(/\/+$/, '');

function vaultUrl(path) {
  return baseUrl + '/vault/' + encodeURI(path);
}

async function obsidianGet(path) {
  return await this.helpers.httpRequest({
    method: 'GET',
    url: vaultUrl(path),
    headers: {
      Authorization: 'Bearer ' + ctx.obsidian_rest_api_key,
    },
    json: false,
    skipSslCertificateValidation: !!ctx.allow_insecure_tls,
  });
}

async function readRequiredTextFile(path) {
  try {
    const text = await obsidianGet.call(this, path);
    const normalized = String(text || '').trim();
    if (!normalized) {
      throw new Error('Prompt file is empty: ' + path);
    }
    return normalized;
  } catch (error) {
    const status = Number(
      (error && (error.statusCode || error.status || error.httpCode)) ||
      (error && error.response ? (error.response.status || error.response.statusCode || 0) : 0)
    );
    const isNotFound = status === 404 || /status code 404|\b404\b/i.test(String(error && error.message ? error.message : ''));
    if (isNotFound) {
      throw new Error('Required prompt file missing: ' + path);
    }
    throw new Error('Obsidian read failed for "' + path + '": ' + (error.message || 'unknown error'));
  }
}

const promptPaths = {
  agent1_research: ctx.workflow_prompts_dir + '/agent1_research.md',
  agent2_topic_fit: ctx.workflow_prompts_dir + '/agent2_topic_fit.md',
  agent3_draft: ctx.workflow_prompts_dir + '/agent3_draft.md',
  agent4_ai_sounding_critic: ctx.workflow_prompts_dir + '/agent4_ai_sounding_critic.md',
  agent6_strategy_critic: ctx.workflow_prompts_dir + '/agent6_strategy_critic.md',
  agent7_strategy_critic: ctx.workflow_prompts_dir + '/agent7_strategy_critic.md',
  platform_linkedin: ctx.workflow_prompts_dir + '/platform_linkedin.md',
  platform_reddit: ctx.workflow_prompts_dir + '/platform_reddit.md',
  qwen_step_summary: ctx.workflow_prompts_dir + '/qwen_step_summary.md',
};

for (const [key, path] of Object.entries(promptPaths)) {
  ctx.prompts[key] = await readRequiredTextFile.call(this, path);
}

return [{ json: ctx }];

const ctx = (items[0] && items[0].json) ? items[0].json : {};

return [{
  json: {
    run_id: ctx.run_id,
    execution_id: ctx.execution_id,
    status: ctx.status,
    topic: ctx.topic,
    model_used: ctx.model_used,
    workflow_log_path: ctx.output_paths && ctx.output_paths.workflow_log,
    linkedin_research_path: ctx.output_paths && ctx.output_paths.linkedin_research,
    reddit_research_path: ctx.output_paths && ctx.output_paths.reddit_research,
    linkedin_draft_path: ctx.output_paths && ctx.output_paths.linkedin_draft,
    reddit_draft_path: ctx.output_paths && ctx.output_paths.reddit_draft,
    workflow_results_index: ctx.workflow_results_index,
    workflow_intermediate_file: ctx.workflow_intermediate_file,
    workflow_steps_file: ctx.workflow_steps_file,
    workflow_overview_file: ctx.workflow_overview_file,
  },
}];
